  raceType: string;       // "HANDİKAP 1-55"
  hasAltili: boolean;
  altiliNo: number | null; // 1 or 2
  // Yeni alanlar
  mesafe: number | null;          // metre (ör: 900)
  kosul: string;                  // "ŞARTLI, 2 Yaşlı İngilizler, 57 kg"
  eld: string;                    // "0:52:05"
